diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9ff1e3aa5502..94aa000bd64e 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -5155,6 +5155,71 @@ Instruction *InstCombinerImpl::foldICmpBinOp(ICmpInst &I,
     }
   }

+  {
+    // icmp (binop X, C), X --> icmp (flipped) X, 0 (or other constant)
+    // Handles SDiv, UDiv, LShr, AShr with constant operand.
+    BinaryOperator *BO = nullptr;
+    if (BO0 && Op1 == BO0->getOperand(0))
+      BO = BO0;
+    else if (BO1 && Op0 == BO1->getOperand(0))
+      BO = BO1;
+    if (BO) {
+      const APInt *C;
+      if (match(BO->getOperand(1), m_APInt(C))) {
+        ICmpInst::Predicate NormalizedPred =
+            BO == BO0 ? Pred : ICmpInst::getSwappedPredicate(Pred);
+        bool IsEQ = NormalizedPred == ICmpInst::ICMP_EQ;
+        bool IsSLT = NormalizedPred == ICmpInst::ICMP_SLT;
+        bool IsSLE = NormalizedPred == ICmpInst::ICMP_SLE;
+        bool IsSGE = NormalizedPred == ICmpInst::ICMP_SGE;
+
+        switch (BO->getOpcode()) {
+        case Instruction::SDiv:
+          if (IsEQ && !C->isOne())
+            return new ICmpInst(ICmpInst::ICMP_EQ, BO->getOperand(0),
+                                Constant::getNullValue(BO->getType()));
+          if (IsSLT && !C->isOne())
+            return new ICmpInst(ICmpInst::ICMP_SGT, BO->getOperand(0),
+                                Constant::getNullValue(BO->getType()));
+          if (IsSGE && !C->isOne())
+            return new ICmpInst(ICmpInst::ICMP_SLE, BO->getOperand(0),
+                                Constant::getNullValue(BO->getType()));
+          break;
+        case Instruction::UDiv:
+          if (IsEQ && !C->isOne())
+            return new ICmpInst(ICmpInst::ICMP_EQ, BO->getOperand(0),
+                                Constant::getNullValue(BO->getType()));
+          if (IsSLT && !C->isOne())
+            return new ICmpInst(ICmpInst::ICMP_SGT, BO->getOperand(0),
+                                Constant::getNullValue(BO->getType()));
+          break;
+        case Instruction::LShr:
+          if (!C->isZero()) {
+            if (IsEQ)
+              return new ICmpInst(ICmpInst::ICMP_EQ, BO->getOperand(0),
+                                  Constant::getNullValue(BO->getType()));
+            if (IsSLE)
+              return new ICmpInst(ICmpInst::ICMP_SGT, BO->getOperand(0),
+                                  Constant::getAllOnesValue(BO->getType()));
+            if (IsSGE)
+              return new ICmpInst(ICmpInst::ICMP_SLT, BO->getOperand(0),
+                                  ConstantInt::get(BO->getType(), 1));
+          }
+          break;
+        case Instruction::AShr:
+          if (!C->isZero()) {
+            if (IsSGE)
+              return new ICmpInst(ICmpInst::ICMP_SLT, BO->getOperand(0),
+                                  ConstantInt::get(BO->getType(), 1));
+            if (IsSLT)
+              return new ICmpInst(ICmpInst::ICMP_SGT, BO->getOperand(0),
+                                  Constant::getNullValue(BO->getType()));
+          }
+          break;
+        }
+      }
+    }
+  }
   if (BO0 && BO1 && BO0->getOpcode() == BO1->getOpcode() &&
       (BO0->hasOneUse() || BO1->hasOneUse()) &&
       BO0->getOperand(1) == BO1->getOperand(1)) {

